int spfy_baked_pos_lookup(const char *w, spfy_pos_class_t *out) {
    if (!w || !*w || !out) return 0;
    int lo = 0, hi = (int)BAKED_POS_N;
    while (lo < hi) {
        int mid = lo + (hi - lo) / 2;
        int cmp = strcmp(w, POS_WORDS[mid]);
        if (cmp == 0) {
            *out = (spfy_pos_class_t)POS_CLASSES[mid];
            return 1;
        }
        if (cmp < 0) hi = mid; else lo = mid + 1;
    }
    *out = POS_UNKNOWN;
    return 0;
}

int spfy_pos_is_open_class(spfy_pos_class_t p) {
    switch (p) {
        case POS_ADJ:
        case POS_ADJ_ADV:
        case POS_ADV:
        case POS_INTERJ:
        case POS_NOUN:
        case POS_NOUN_ADJ:
        case POS_NOUN_VERB:
        case POS_NOUN_VERB_ADJ:
        case POS_PREP:
        case POS_PRO:
        case POS_PRO2:
        case POS_QUANT:
        case POS_UNDEF:
        case POS_VERB:
        case POS_VERB_ADJ:
        case POS_WH:
            return 1;
        default:
            return 0;
    }
}
